payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "硬件攻坚阶段",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构。"
    },
    {
      "date": "第3月",
      "title": "算法开发阶段",
      "description": "开发分层CNN-LSTM手势识别模型与自适应滑动窗口分割模块，实现毫秒级实时推理；构建统一时空对齐协议，支持多模态低延迟融合。"
    },
    {
      "date": "第4月",
      "title": "系统集成阶段",
      "description": "嵌入压力/温度动态反馈执行单元，集成感知-意图-反馈闭环；联调H-Box全息舱与李未可眼镜等合作设备接口。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化阶段",
      "description": "在工业远程操控与虚拟实训等场景开展压力测试，基于用户反馈迭代优化交互体验，形成可复用的标准接口。"
    }
  ]
}

